Bash(MSYS_NO_PATHCONV=1 docker exec mock_mssql /opt/mssql-tools18/bin/sqlcmd -S localhost -U sa -P "Test1234!" -C -d mockdb -Q "
DECLARE @i INT = 1;
WHILE @i <= 2000 BEGIN
  INSERT INTO customers \(name, email, phone, city\) VALUES \('User_'+CAST\(@i AS VARCHAR\), 'user'+CAST\(@i AS VARCHAR\)+'@test.com', '05'+RIGHT\('000000000'+CAST\(ABS\(CHECKSUM\(NEWID\(\)\)\)%999999999 AS VARCHAR\),9\), CHOOSE\(1+ABS\(CHECKSUM\(NEWID\(\)\)\)%5,'Istanbul','Ankara','Izmir','Bursa','Antalya'\)\);
  SET @i = @i + 1;
END;
DECLARE @j INT = 1;
WHILE @j <= 3000 BEGIN
  INSERT INTO orders \(customer_id, amount, status, order_date\) VALUES \(1+ABS\(CHECKSUM\(NEWID\(\)\)\)%2000, CAST\(RAND\(CHECKSUM\(NEWID\(\)\)\)*1000 AS DECIMAL\(10,2\)\), CHOOSE\(1+ABS\(CHECKSUM\(NEWID\(\)\)\)%4,'pending','shipped','delivered','cancelled'\), DATEADD\(DAY,-ABS\(CHECKSUM\(NEWID\(\)\)\)%365,GETDATE\(\)\)\);
  SET @j = @j + 1;
END;
DECLARE @k INT = 1;
WHILE @k <= 1000 BEGIN
  INSERT INTO products \(name, category, price, stock, sku\) VALUES \('Product_'+CAST\(@k AS VARCHAR\), CHOOSE\(1+ABS\(CHECKSUM\(NEWID\(\)\)\)%5,'Electronics','Books','Clothing','Food','Sports'\), CAST\(RAND\(CHECKSUM\(NEWID\(\)\)\)*500+1 AS DECIMAL\(10,2\)\), ABS\(CHECKSUM\(NEWID\(\)\)\)%1000, 'SKU-'+RIGHT\('000000'+CAST\(@k AS VARCHAR\),6\)\);
  SET @k = @k + 1;
END;
" 2>&1)

